#!/usr/bin/env node
/* sprint2.mjs — applies Sprint 2 (intelligence: search + timeline + PDF ingest). Overwrites listed files. */
import { mkdirSync, writeFileSync } from "node:fs";
import { dirname } from "node:path";
const FILES=[
  ["package.json", ""],
  ["PROJECT_LOG.md", ""],
  ["src/main/db/migrations/0002_fts_contentful.sql", ""],
  ["src/main/db/database.ts", ""],
  ["src/main/db/search.repo.ts", ""],
  ["src/main/services/extraction/pdf.ts", ""],
  ["src/main/services/intelligence/ingest.ts", ""],
  ["src/main/ipc/index.ts", ""],
  ["src/preload/index.ts", ""],
  ["src/preload/index.d.ts", ""],
  ["src/renderer/src/App.tsx", ""],
  ["src/renderer/src/assets/main.css", ""]
];
let n=0; for(const [rel,b64] of FILES){ mkdirSync(dirname(rel),{recursive:true}); writeFileSync(rel,Buffer.from(b64,"base64")); n++; }
console.log(`✅ Sprint 2 applied: ${n} files written/updated.`);
console.log("Next: npm install  &&  npm run dev   (migration 0002 runs automatically)");
